/* =====================================================================
   AURA ALPHA — TradingView Webhook Management
   Full webhook integration: setup wizard, API key CRUD, delivery log,
   signal history, test endpoint, TradingView configuration guide.
   HIGH ROI feature — TradingView has 50M+ users.
   ===================================================================== */
import { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedPage from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { api, apiPost, apiDelete } from '../utils/api';
import { tokens } from '../styles/tokens';
import s from './WebhookManagementPage.module.css';

// ── Design tokens ────────────────────────────────────────────────────────
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};

// ── Helpers ──────────────────────────────────────────────────────────────
const fmtTime = (ts) => {
  if (!ts) return '--';
  try {
    const d = new Date(ts);
    if (isNaN(d.getTime())) return ts;
    return d.toLocaleString('en-US', {
      month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false,
    });
  } catch { return ts; }
};

const statusColor = (code) => {
  if (!code) return C.textSec;
  if (code >= 200 && code < 300) return C.green;
  if (code >= 400 && code < 500) return C.amber;
  return C.red;
};

// ── Sub-components ───────────────────────────────────────────────────────
function GlassPanel({ children, className = '', style }) {
  return <div className={`${s.glassPanel} ${className}`} style={style}>{children}</div>;
}

function SectionHeader({ title, sub }) {
  return (
    <div className={s.sectionHeader}>
      <div className={s.sectionTitle}>{title}</div>
      {sub && <div className={s.sectionSub}>{sub}</div>}
    </div>
  );
}

function TabBtn({ label, active, onClick, count }) {
  return (
    <button onClick={onClick} className={`${s.tabBtn} ${active ? s.tabBtnActive : s.tabBtnInactive}`}>
      {label}
      {count !== undefined && <span className={s.tabCount}>{count}</span>}
    </button>
  );
}

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };
  return (
    <button onClick={handleCopy} className={`${s.copyBtn} ${copied ? s.copyBtnCopied : s.copyBtnDefault}`}>
      {copied ? 'Copied' : 'Copy'}
    </button>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ════════════════════════════════════════════════════════════════════════════
export default function WebhookManagementPage() {
  usePageTitle('TradingView Webhooks');
  const isMobile = useIsMobile();

  // ── State ──────────────────────────────────────────────────────────────
  const [tab, setTab] = useState('setup');
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState(null);

  // Setup state
  const [tvSetup, setTvSetup] = useState(null);
  const [tvKeyRevealed, setTvKeyRevealed] = useState(false);
  const [tvSettingUp, setTvSettingUp] = useState(false);

  // API Keys state
  const [apiKeys, setApiKeys] = useState([]);
  const [keysLoading, setKeysLoading] = useState(false);
  const [newKey, setNewKey] = useState(null); // freshly created key (shown once)
  const [newKeyLabel, setNewKeyLabel] = useState('');
  const [creatingKey, setCreatingKey] = useState(false);
  const [revokingKeyId, setRevokingKeyId] = useState(null);

  // Delivery log state
  const [deliveries, setDeliveries] = useState([]);
  const [deliveriesLoading, setDeliveriesLoading] = useState(false);
  const [expandedDelivery, setExpandedDelivery] = useState(null);

  // Signal history state
  const [signals, setSignals] = useState([]);
  const [signalsLoading, setSignalsLoading] = useState(false);

  // Test state
  const [tvTestSymbol, setTvTestSymbol] = useState('AAPL');
  const [tvTestSide, setTvTestSide] = useState('buy');
  const [tvTestPrice, setTvTestPrice] = useState('185.50');
  const [tvTestQty, setTvTestQty] = useState('10');
  const [tvTestFormat, setTvTestFormat] = useState('json');
  const [tvTesting, setTvTesting] = useState(false);
  const [tvTestResult, setTvTestResult] = useState(null);

  // Audit events state
  const [auditEvents, setAuditEvents] = useState([]);
  const [auditLoading, setAuditLoading] = useState(false);

  const abortRef = useRef(null);

  // ── Data loading ───────────────────────────────────────────────────────
  const showMsg = (type, text) => {
    setMsg({ type, text });
    setTimeout(() => setMsg(null), 5000);
  };

  // Fetch webhook config (check if setup exists)
  const fetchConfig = useCallback(async (signal) => {
    const data = await api('/webhooks/tradingview/config', { signal, silent: true });
    if (data?.webhook_url) {
      setTvSetup({
        webhook_url: data.webhook_url,
        has_active_keys: data.has_active_keys || false,
        supported_formats: data.supported_formats || {},
        templates: data.templates || data.supported_formats || {},
      });
    }
    return data;
  }, []);

  // Fetch API keys
  const fetchApiKeys = useCallback(async (signal) => {
    setKeysLoading(true);
    const data = await api('/webhooks/keys', { signal, silent: true });
    if (data?.keys) {
      setApiKeys(data.keys);
    } else if (Array.isArray(data)) {
      setApiKeys(data);
    }
    setKeysLoading(false);
  }, []);

  // Fetch delivery log
  const fetchDeliveries = useCallback(async (signal) => {
    setDeliveriesLoading(true);
    const data = await api('/webhooks/tradingview/deliveries?limit=50', { signal, silent: true });
    if (data?.deliveries) {
      setDeliveries(data.deliveries);
    } else if (Array.isArray(data)) {
      setDeliveries(data);
    }
    setDeliveriesLoading(false);
  }, []);

  // Fetch signal history
  const fetchSignals = useCallback(async (signal) => {
    setSignalsLoading(true);
    const data = await api('/webhooks/tradingview/history?limit=50', { signal, silent: true });
    if (data?.signals) {
      setSignals(data.signals);
    } else if (data?.history) {
      setSignals(data.history);
    } else if (Array.isArray(data)) {
      setSignals(data);
    }
    setSignalsLoading(false);
  }, []);

  // Fetch audit events
  const fetchAuditEvents = useCallback(async (signal) => {
    setAuditLoading(true);
    const data = await api('/webhooks/events?limit=50', { signal, silent: true });
    if (data?.events) {
      setAuditEvents(data.events);
    } else if (Array.isArray(data)) {
      setAuditEvents(data);
    }
    setAuditLoading(false);
  }, []);

  // Initial load
  useEffect(() => {
    const ac = new AbortController();
    abortRef.current = ac;
    async function loadInitial() {
      setLoading(true);
      await fetchConfig(ac.signal);
      setLoading(false);
    }
    loadInitial();
    return () => ac.abort();
  }, [fetchConfig]);

  // Tab-specific data loading
  useEffect(() => {
    const signal = abortRef.current?.signal;
    if (!signal || signal.aborted) return;

    if (tab === 'keys') fetchApiKeys(signal);
    if (tab === 'deliveries') fetchDeliveries(signal);
    if (tab === 'signals') fetchSignals(signal);
    if (tab === 'audit') fetchAuditEvents(signal);
  }, [tab, fetchApiKeys, fetchDeliveries, fetchSignals, fetchAuditEvents]);

  // Auto-refresh deliveries when on that tab
  useEffect(() => {
    if (tab !== 'deliveries') return;
    const iv = setInterval(() => {
      const signal = abortRef.current?.signal;
      if (signal && !signal.aborted) fetchDeliveries(signal);
    }, 30000);
    return () => clearInterval(iv);
  }, [tab, fetchDeliveries]);

  // ── TradingView Setup ─────────────────────────────────────────────────
  const handleTvSetup = async () => {
    setTvSettingUp(true);
    const data = await apiPost('/webhooks/tradingview/setup', { label: 'TradingView Integration' });
    if (data?.webhook_url) {
      setTvSetup({
        webhook_url: data.webhook_url,
        api_key: data.api_key,
        api_key_masked: data.api_key_masked,
        key_id: data.key_id,
        templates: data.templates || {},
        setup_steps: data.setup_steps,
        bot_routing: data.bot_routing,
        has_active_keys: true,
        fresh: true,
      });
      setTvKeyRevealed(true);
      showMsg('ok', 'TradingView webhook URL generated successfully');
    } else {
      showMsg('error', data?.detail || 'Failed to generate webhook URL');
    }
    setTvSettingUp(false);
  };

  // ── API Key Actions ───────────────────────────────────────────────────
  const handleCreateKey = async () => {
    if (!newKeyLabel.trim()) {
      showMsg('error', 'Please enter a label for the API key');
      return;
    }
    setCreatingKey(true);
    const data = await apiPost('/webhooks/keys', { label: newKeyLabel.trim() });
    if (data?.key || data?.api_key) {
      const key = data.key || data.api_key;
      const keyObj = {
        id: data.key_id || data.id,
        key_masked: data.key_masked || (key.slice(0, 8) + '...' + key.slice(-4)),
        label: newKeyLabel.trim(),
        status: 'active',
        created_at: data.created_at || new Date().toISOString(),
      };
      setNewKey({ ...keyObj, key_full: key });
      setApiKeys(prev => [keyObj, ...prev]);
      setNewKeyLabel('');
      showMsg('ok', 'API key created successfully');
    } else {
      showMsg('error', data?.detail || 'Failed to create API key');
    }
    setCreatingKey(false);
  };

  const handleRevokeKey = async (keyId) => {
    if (!confirm('Revoke this API key? Webhooks using this key will stop working.')) return;
    setRevokingKeyId(keyId);
    const data = await apiDelete(`/webhooks/keys/${keyId}`);
    if (data?.status === 'revoked' || data?.message || !data?.detail) {
      setApiKeys(prev => prev.map(k =>
        k.id === keyId ? { ...k, status: 'revoked' } : k
      ));
      showMsg('ok', 'API key revoked');
    } else {
      showMsg('error', data?.detail || 'Failed to revoke key');
    }
    setRevokingKeyId(null);
  };

  // ── Test Signal ───────────────────────────────────────────────────────
  const handleTvTest = async () => {
    setTvTesting(true);
    setTvTestResult(null);
    const data = await apiPost('/webhooks/tradingview/test', {
      symbol: tvTestSymbol.toUpperCase(),
      side: tvTestSide,
      price: parseFloat(tvTestPrice) || null,
      quantity: parseFloat(tvTestQty) || null,
      strategy: 'TradingView Test',
      format: tvTestFormat,
    });
    if (data) {
      setTvTestResult(data);
      if (data.status?.includes('accepted') || data.status === 'ok' || data.signal_id) {
        showMsg('ok', `Test signal accepted: ${tvTestSide.toUpperCase()} ${tvTestSymbol.toUpperCase()}`);
      } else {
        showMsg('error', `Test signal: ${data.status || 'unknown'} -- ${(data.errors || []).join(', ') || data.message || 'see details below'}`);
      }
    } else {
      showMsg('error', 'Test failed -- no response from server');
    }
    setTvTesting(false);
    // Refresh deliveries + signals
    const signal = abortRef.current?.signal;
    if (signal && !signal.aborted) {
      fetchDeliveries(signal);
      fetchSignals(signal);
    }
  };

  const pad = isMobile ? 16 : 24;

  return (
    <AnimatedPage>
      <div className={`${s.page} ${isMobile ? s.pageMobile : ''}`}>
        {/* Header */}
        <div className={s.header}>
          <h1 className={s.headerTitle}>TradingView Webhooks</h1>
          <p className={s.headerSub}>
            Connect TradingView alerts directly to Aura Alpha. Generate a webhook URL,
            manage API keys, and monitor incoming signals in real time.
          </p>
        </div>

        {/* Tabs */}
        <div className={s.tabRow}>
          <TabBtn label="Setup" active={tab === 'setup'} onClick={() => setTab('setup')} />
          <TabBtn label="API Keys" active={tab === 'keys'} onClick={() => setTab('keys')} count={apiKeys.filter(k => k.status === 'active').length || undefined} />
          <TabBtn label="Deliveries" active={tab === 'deliveries'} onClick={() => setTab('deliveries')} count={deliveries.length || undefined} />
          <TabBtn label="Signal History" active={tab === 'signals'} onClick={() => setTab('signals')} count={signals.length || undefined} />
          <TabBtn label="Test" active={tab === 'test'} onClick={() => setTab('test')} />
          <TabBtn label="Guide" active={tab === 'guide'} onClick={() => setTab('guide')} />
          <TabBtn label="Audit Log" active={tab === 'audit'} onClick={() => setTab('audit')} />
        </div>

        {/* Toast */}
        <AnimatePresence>
          {msg && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              className={`${s.toast} ${msg.type === 'ok' ? s.toastOk : s.toastError}`}
            >
              {msg.text}
            </motion.div>
          )}
        </AnimatePresence>

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* SETUP TAB                                                      */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'setup' && (
          <div>
            <GlassPanel className={s.tvSetupCard} style={{ padding: pad }}>
              <div className={s.tvHeader}>
                <div className={s.tvLogo}>TV</div>
                <div>
                  <h2 className={s.tvTitle}>Connect TradingView</h2>
                  <span className={s.tvBadge}>50M+ Users</span>
                </div>
              </div>
              <p className={s.tvSubtitle}>
                Route TradingView alerts directly to Aura Alpha for automatic execution.
                Create any alert on TradingView, point it at your unique webhook URL, and
                signals flow through our risk engine to your preferred bot.
              </p>

              {loading ? (
                <div className={s.emptyState}>Loading configuration...</div>
              ) : !tvSetup?.has_active_keys ? (
                /* No key yet -- show setup button */
                <div>
                  <p style={{ fontSize: 13, color: C.textSec, marginBottom: 16 }}>
                    Click below to generate your unique webhook URL and API key.
                    You can create additional keys in the API Keys tab.
                  </p>
                  <button
                    onClick={handleTvSetup}
                    disabled={tvSettingUp}
                    className={s.tvSetupBtn}
                  >
                    {tvSettingUp ? 'Generating...' : 'Generate Webhook URL + API Key'}
                  </button>
                </div>
              ) : (
                /* Key exists -- show URL + secret */
                <div>
                  <SectionHeader title="Your Webhook URL" sub="Paste this into TradingView's webhook URL field" />
                  <div className={s.tvUrlBox}>
                    <code className={s.tvUrlText}>{tvSetup.webhook_url}</code>
                    <CopyButton text={tvSetup.webhook_url} />
                  </div>

                  {tvSetup.api_key && (
                    <>
                      <SectionHeader title="Your API Key" sub="Keep this secret -- it authenticates your webhook calls" />
                      <div className={s.tvKeyBox}>
                        <code className={s.tvKeyText}>
                          {tvKeyRevealed ? tvSetup.api_key : '\u2022'.repeat(24)}
                        </code>
                        <button onClick={() => setTvKeyRevealed(!tvKeyRevealed)} className={s.secretToggle}>
                          {tvKeyRevealed ? 'Hide' : 'Reveal'}
                        </button>
                        {tvKeyRevealed && <CopyButton text={tvSetup.api_key} />}
                      </div>
                    </>
                  )}

                  {tvSetup.fresh && (
                    <div style={{
                      fontSize: 12, color: C.amber, marginTop: 8,
                      fontFamily: 'var(--font-mono)', lineHeight: 1.6,
                    }}>
                      Save your API key now -- it will not be shown again in full after you leave this page.
                    </div>
                  )}

                  {/* Regenerate button */}
                  <div style={{ marginTop: 16, display: 'flex', gap: 10 }}>
                    <button
                      onClick={handleTvSetup}
                      disabled={tvSettingUp}
                      className={s.actionBtn}
                    >
                      {tvSettingUp ? 'Generating...' : 'Generate New Key'}
                    </button>
                    <button
                      onClick={() => setTab('keys')}
                      className={s.actionBtn}
                    >
                      Manage API Keys
                    </button>
                  </div>
                </div>
              )}
            </GlassPanel>

            {/* Quick status cards */}
            {tvSetup?.has_active_keys && (
              <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : 'repeat(3, 1fr)', gap: 16, marginBottom: 20 }}>
                <GlassPanel style={{ padding: 16 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: C.textSec, marginBottom: 6 }}>Active Keys</div>
                  <div style={{ fontSize: 22, fontWeight: 700, fontFamily: 'var(--font-mono)', color: C.green }}>
                    {apiKeys.filter(k => k.status === 'active').length || '--'}
                  </div>
                </GlassPanel>
                <GlassPanel style={{ padding: 16 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: C.textSec, marginBottom: 6 }}>Recent Signals</div>
                  <div style={{ fontSize: 22, fontWeight: 700, fontFamily: 'var(--font-mono)', color: C.blue }}>
                    {signals.length || '--'}
                  </div>
                </GlassPanel>
                <GlassPanel style={{ padding: 16 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: C.textSec, marginBottom: 6 }}>Deliveries</div>
                  <div style={{ fontSize: 22, fontWeight: 700, fontFamily: 'var(--font-mono)', color: C.purple }}>
                    {deliveries.length || '--'}
                  </div>
                </GlassPanel>
              </div>
            )}

            {/* Signal Routing */}
            <GlassPanel className={s.tvSetupCard} style={{ padding: pad }}>
              <SectionHeader title="Signal Routing" sub="Signals are automatically routed to the appropriate bot based on symbol type" />
              <div className={s.tvRoutingCard}>
                <div className={s.tvRoute}>
                  <div className={s.tvRouteName} style={{ color: C.green }}>SHAWN / SHANE</div>
                  <div className={s.tvRouteDesc}>US equities and ETFs (AAPL, TSLA, SPY, QQQ, etc.) are routed to equity bots during market hours.</div>
                </div>
                <div className={s.tvRoute}>
                  <div className={s.tvRouteName} style={{ color: C.amber }}>Paper Trading</div>
                  <div className={s.tvRouteDesc}>Default mode for new users. All signals execute in paper mode until you enable live trading.</div>
                </div>
              </div>
            </GlassPanel>
          </div>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* API KEYS TAB                                                   */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'keys' && (
          <div>
            {/* Create new key */}
            <GlassPanel style={{ padding: pad }}>
              <SectionHeader title="Create API Key" sub="Generate a new API key for TradingView webhook authentication" />
              <div style={{ display: 'flex', gap: 12, alignItems: 'flex-end', flexWrap: 'wrap' }}>
                <div className={s.formGroup} style={{ flex: 1, minWidth: 200, marginBottom: 0 }}>
                  <label className={s.formLabel}>Key Label</label>
                  <input
                    type="text"
                    value={newKeyLabel}
                    onChange={e => setNewKeyLabel(e.target.value)}
                    placeholder="e.g., TradingView Main, BTC Strategy, etc."
                    className={s.formInput}
                    onKeyDown={e => e.key === 'Enter' && handleCreateKey()}
                  />
                </div>
                <button
                  onClick={handleCreateKey}
                  disabled={creatingKey || !newKeyLabel.trim()}
                  className={s.saveBtn}
                  style={{ marginBottom: 0 }}
                >
                  {creatingKey ? 'Creating...' : 'Create Key'}
                </button>
              </div>
            </GlassPanel>

            {/* Newly created key banner */}
            <AnimatePresence>
              {newKey && (
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  exit={{ opacity: 0, height: 0 }}
                  style={{ overflow: 'hidden' }}
                >
                  <div className={s.newKeyBanner}>
                    <div className={s.newKeyTitle}>New API Key Created -- Copy It Now</div>
                    <div className={s.newKeyValue}>
                      <code className={s.newKeyText}>{newKey.key_full}</code>
                      <CopyButton text={newKey.key_full} />
                    </div>
                    <div className={s.newKeyWarning}>
                      This is the only time the full key will be displayed. Save it securely.
                      <button
                        onClick={() => setNewKey(null)}
                        style={{
                          marginLeft: 12, background: 'none', border: 'none',
                          color: C.textSec, cursor: 'pointer', fontSize: 11,
                          fontFamily: 'var(--font-mono)', textDecoration: 'underline',
                        }}
                      >
                        Dismiss
                      </button>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>

            {/* Keys table */}
            <GlassPanel style={{ padding: 0 }}>
              <div style={{ padding: `${pad}px ${pad}px 12px` }}>
                <div className={s.sectionHeaderRow}>
                  <SectionHeader title="Active API Keys" sub="Keys used to authenticate TradingView webhook calls" />
                  <button
                    onClick={() => fetchApiKeys(abortRef.current?.signal)}
                    className={s.actionBtn}
                  >
                    Refresh
                  </button>
                </div>
              </div>
              {keysLoading ? (
                <div className={s.emptyState}>Loading API keys...</div>
              ) : apiKeys.length === 0 ? (
                <div className={s.emptyState}>
                  No API keys yet. Create one above to start receiving TradingView webhooks.
                </div>
              ) : (
                <div className={s.keysTableWrap}>
                  <table className={s.keysTable}>
                    <thead>
                      <tr>
                        <th className={s.keysTableTh}>Label</th>
                        <th className={s.keysTableTh}>Key</th>
                        <th className={s.keysTableTh}>Status</th>
                        <th className={s.keysTableTh}>Created</th>
                        <th className={s.keysTableTh}>Last Used</th>
                        <th className={s.keysTableTh}></th>
                      </tr>
                    </thead>
                    <tbody>
                      {apiKeys.map((k) => (
                        <tr key={k.id}>
                          <td className={s.keysTableTd} style={{ fontWeight: 600 }}>
                            {k.label || k.name || 'Unnamed'}
                          </td>
                          <td className={s.keysTableTd}>
                            <span className={s.keyValue}>
                              {k.key_masked || k.key_prefix || '\u2022'.repeat(16)}
                            </span>
                          </td>
                          <td className={s.keysTableTd}>
                            <span className={`${s.statusBadge} ${k.status === 'active' ? s.statusActive : s.statusRevoked}`}>
                              {k.status}
                            </span>
                          </td>
                          <td className={s.keysTableTd} style={{ color: C.textSec, whiteSpace: 'nowrap' }}>
                            {fmtTime(k.created_at)}
                          </td>
                          <td className={s.keysTableTd} style={{ color: C.textSec, whiteSpace: 'nowrap' }}>
                            {fmtTime(k.last_used_at || k.last_used)}
                          </td>
                          <td className={s.keysTableTd} style={{ textAlign: 'right' }}>
                            {k.status === 'active' && (
                              <button
                                onClick={() => handleRevokeKey(k.id)}
                                disabled={revokingKeyId === k.id}
                                className={s.revokeBtn}
                              >
                                {revokingKeyId === k.id ? 'Revoking...' : 'Revoke'}
                              </button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </GlassPanel>
          </div>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* DELIVERIES TAB                                                 */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'deliveries' && (
          <GlassPanel style={{ padding: 0 }}>
            <div style={{ padding: `${pad}px ${pad}px 12px` }}>
              <div className={s.sectionHeaderRow}>
                <SectionHeader
                  title="Webhook Delivery Log"
                  sub="Recent incoming TradingView webhook deliveries with status. Auto-refreshes every 30 seconds."
                />
                <button
                  onClick={() => fetchDeliveries(abortRef.current?.signal)}
                  className={s.actionBtn}
                >
                  Refresh
                </button>
              </div>
            </div>
            {deliveriesLoading ? (
              <div className={s.emptyState}>Loading delivery log...</div>
            ) : deliveries.length === 0 ? (
              <div className={s.emptyState}>
                No webhook deliveries yet. Set up your TradingView webhook and create an alert to see deliveries here.
              </div>
            ) : (
              <>
                <div className={s.tableWrap}>
                  <table className={s.table}>
                    <thead>
                      <tr>
                        <th className={s.th}>Time</th>
                        <th className={s.th}>Symbol</th>
                        <th className={s.th}>Side</th>
                        <th className={s.th}>Status</th>
                        <th className={s.th}>Response</th>
                        <th className={s.th}>Source</th>
                        <th className={s.th}>Details</th>
                      </tr>
                    </thead>
                    <tbody>
                      {deliveries.map((del, i) => {
                        const isOk = del.success || del.status_code === 200 ||
                          del.status === 'received' || del.status === 'filled' || del.status === 'submitted';
                        const action = del.action || del.side || '';
                        return (
                          <tr key={del.id || i}>
                            <td className={s.tdMuted}>
                              {fmtTime(del.delivered_at || del.created_at || del.received_at_iso)}
                            </td>
                            <td className={s.tdMono} style={{ fontWeight: 700 }}>
                              {del.symbol || '--'}
                            </td>
                            <td className={s.tdMono} style={{
                              color: action.toLowerCase() === 'buy' ? '#22C55E'
                                : action.toLowerCase() === 'sell' ? '#EF4444'
                                : C.textSec,
                              fontWeight: 700,
                            }}>
                              {action.toUpperCase() || '--'}
                            </td>
                            <td className={s.tdMono}>
                              {del.status_code ? (
                                <span style={{ color: statusColor(del.status_code) }}>
                                  {del.status_code}
                                </span>
                              ) : (
                                <span style={{
                                  display: 'inline-block',
                                  padding: '2px 8px',
                                  borderRadius: 4,
                                  fontSize: 10,
                                  fontWeight: 700,
                                  textTransform: 'uppercase',
                                  background: isOk ? 'rgba(34,197,94,0.12)' : 'rgba(239,68,68,0.12)',
                                  color: isOk ? '#22C55E' : '#EF4444',
                                }}>
                                  {del.status || 'unknown'}
                                </span>
                              )}
                            </td>
                            <td className={s.tdMono}>
                              {del.response_time_ms != null ? `${del.response_time_ms}ms` : '--'}
                            </td>
                            <td className={s.tdTruncate}>
                              {del.source || del.key_label || 'TradingView'}
                            </td>
                            <td>
                              <button
                                onClick={() => setExpandedDelivery(expandedDelivery === (del.id || i) ? null : (del.id || i))}
                                className={s.detailBtn}
                              >
                                {expandedDelivery === (del.id || i) ? 'Hide' : 'View'}
                              </button>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>

                {/* Expanded delivery detail */}
                <AnimatePresence>
                  {expandedDelivery != null && (
                    <motion.div
                      initial={{ opacity: 0, height: 0 }}
                      animate={{ opacity: 1, height: 'auto' }}
                      exit={{ opacity: 0, height: 0 }}
                      style={{ overflow: 'hidden' }}
                    >
                      {deliveries.filter(d => (d.id || deliveries.indexOf(d)) === expandedDelivery).map((del, i) => (
                        <div key={del.id || i} className={s.deliveryDetail}>
                          <div className={s.deliveryDetailHeader}>
                            <span className={s.deliveryDetailTitle}>Payload / Details</span>
                            {del.error && <span className={s.deliveryDetailError}>{del.error}</span>}
                          </div>
                          <pre className={s.deliveryPayload}>
                            {del.payload
                              ? (typeof del.payload === 'string' ? del.payload : JSON.stringify(del.payload, null, 2))
                              : JSON.stringify(del, null, 2)}
                          </pre>
                        </div>
                      ))}
                    </motion.div>
                  )}
                </AnimatePresence>
              </>
            )}
          </GlassPanel>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* SIGNAL HISTORY TAB                                             */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'signals' && (
          <GlassPanel style={{ padding: 0 }}>
            <div style={{ padding: `${pad}px ${pad}px 12px` }}>
              <div className={s.sectionHeaderRow}>
                <SectionHeader
                  title="Signal History"
                  sub="Signals received from TradingView webhooks, showing parsed symbol, side, price, and execution status."
                />
                <button
                  onClick={() => fetchSignals(abortRef.current?.signal)}
                  className={s.actionBtn}
                >
                  Refresh
                </button>
              </div>
            </div>
            {signalsLoading ? (
              <div className={s.emptyState}>Loading signal history...</div>
            ) : signals.length === 0 ? (
              <div className={s.emptyState}>
                No signals received yet. Once TradingView sends a webhook, parsed signals appear here.
              </div>
            ) : (
              <div>
                {signals.map((sig, i) => {
                  const side = (sig.side || sig.action || '').toLowerCase();
                  const sideClass = side === 'buy' ? s.signalSideBuy
                    : side === 'sell' ? s.signalSideSell
                    : s.signalSideClose;
                  return (
                    <div key={sig.id || sig.signal_id || i} className={s.signalCard}>
                      <span className={s.signalSymbol}>{sig.symbol || '--'}</span>
                      <span className={sideClass}>
                        {(sig.side || sig.action || '--').toUpperCase()}
                      </span>
                      <span className={s.signalMeta}>
                        {sig.price > 0 && (
                          <span className={s.signalMetaItem}>
                            <span className={s.signalMetaLabel}>Price</span>
                            ${Number(sig.price).toFixed(2)}
                          </span>
                        )}
                        {sig.quantity > 0 && (
                          <span className={s.signalMetaItem}>
                            <span className={s.signalMetaLabel}>Qty</span>
                            {sig.quantity}
                          </span>
                        )}
                        {sig.strategy && (
                          <span className={s.signalMetaItem}>
                            <span className={s.signalMetaLabel}>Strategy</span>
                            {sig.strategy}
                          </span>
                        )}
                        {sig.bot && (
                          <span className={s.signalMetaItem}>
                            <span className={s.signalMetaLabel}>Bot</span>
                            {sig.bot}
                          </span>
                        )}
                        {sig.status && (
                          <span className={s.signalMetaItem}>
                            <span style={{
                              display: 'inline-block',
                              padding: '1px 8px',
                              borderRadius: 4,
                              fontSize: 10,
                              fontWeight: 700,
                              textTransform: 'uppercase',
                              background: (sig.status === 'filled' || sig.status === 'executed')
                                ? 'rgba(34,197,94,0.12)'
                                : sig.status === 'rejected'
                                ? 'rgba(239,68,68,0.12)'
                                : 'rgba(245,158,11,0.12)',
                              color: (sig.status === 'filled' || sig.status === 'executed')
                                ? '#22C55E'
                                : sig.status === 'rejected'
                                ? '#EF4444'
                                : '#F59E0B',
                            }}>
                              {sig.status}
                            </span>
                          </span>
                        )}
                        {sig.error && (
                          <span className={s.signalMetaItem} style={{ color: '#EF4444' }}>
                            {sig.error}
                          </span>
                        )}
                      </span>
                      <span className={s.signalTime}>
                        {fmtTime(sig.created_at || sig.received_at || sig.timestamp)}
                      </span>
                    </div>
                  );
                })}
              </div>
            )}
          </GlassPanel>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* TEST TAB                                                       */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'test' && (
          <div>
            <GlassPanel style={{ padding: pad }}>
              <SectionHeader title="Test Your Webhook" sub="Send a simulated TradingView payload to verify your setup works end-to-end" />

              <div className={s.tvTestForm}>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Symbol</label>
                  <input
                    type="text"
                    value={tvTestSymbol}
                    onChange={e => setTvTestSymbol(e.target.value)}
                    placeholder="AAPL"
                    className={s.formInput}
                  />
                </div>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Side</label>
                  <select value={tvTestSide} onChange={e => setTvTestSide(e.target.value)} className={s.formSelect}>
                    <option value="buy">Buy</option>
                    <option value="sell">Sell</option>
                    <option value="close">Close</option>
                  </select>
                </div>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Price</label>
                  <input
                    type="text"
                    value={tvTestPrice}
                    onChange={e => setTvTestPrice(e.target.value)}
                    placeholder="185.50"
                    className={s.formInput}
                  />
                </div>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Quantity</label>
                  <input
                    type="text"
                    value={tvTestQty}
                    onChange={e => setTvTestQty(e.target.value)}
                    placeholder="10"
                    className={s.formInput}
                  />
                </div>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
                <label className={s.formLabel} style={{ margin: 0 }}>Format</label>
                <select value={tvTestFormat} onChange={e => setTvTestFormat(e.target.value)} className={s.testEventSelect}>
                  <option value="json">JSON</option>
                  <option value="text">Text</option>
                  <option value="strategy_template">Strategy Template</option>
                </select>
              </div>

              <button onClick={handleTvTest} disabled={tvTesting || !tvTestSymbol.trim()} className={s.tvTestBtn}>
                {tvTesting ? 'Sending Test Signal...' : 'Send Test Signal'}
              </button>

              {tvTestResult && (
                <div className={`${s.tvTestResult} ${
                  (tvTestResult.status?.includes('accepted') || tvTestResult.status === 'ok' || tvTestResult.signal_id)
                    ? s.tvTestResultOk : s.tvTestResultError
                }`}>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>
                    {(tvTestResult.status?.includes('accepted') || tvTestResult.status === 'ok' || tvTestResult.signal_id)
                      ? 'Signal Accepted' : 'Signal Rejected'}
                  </div>
                  <div>Status: {tvTestResult.status || 'N/A'}</div>
                  {tvTestResult.signal_id && <div>Signal ID: {tvTestResult.signal_id}</div>}
                  {tvTestResult.message && <div>{tvTestResult.message}</div>}
                  {tvTestResult.parsed && (
                    <div style={{ marginTop: 8, padding: 10, background: 'rgba(0,0,0,0.2)', borderRadius: 6 }}>
                      <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: C.textSec, marginBottom: 6 }}>
                        Parsed Signal
                      </div>
                      <pre style={{ margin: 0, fontSize: 11, fontFamily: 'var(--font-mono)', color: C.textSec, whiteSpace: 'pre-wrap' }}>
                        {JSON.stringify(tvTestResult.parsed, null, 2)}
                      </pre>
                    </div>
                  )}
                  {tvTestResult.errors?.length > 0 && (
                    <div style={{ color: '#EF4444', marginTop: 4 }}>
                      Errors: {tvTestResult.errors.join(', ')}
                    </div>
                  )}
                  {tvTestResult.risk && !tvTestResult.risk.approved && (
                    <div style={{ color: C.amber, marginTop: 4 }}>
                      Risk: {tvTestResult.risk.reasons?.join(', ')}
                    </div>
                  )}
                </div>
              )}
            </GlassPanel>

            {/* Preview what TradingView sends */}
            <GlassPanel style={{ padding: pad }}>
              <SectionHeader title="What TradingView Sends" sub="Preview of the payload that TradingView would send for this test" />
              <pre className={s.deliveryPayload}>{JSON.stringify({
                symbol: tvTestSymbol.toUpperCase(),
                side: tvTestSide,
                price: parseFloat(tvTestPrice) || 0,
                quantity: parseInt(tvTestQty) || 0,
                strategy: 'TradingView Test',
                timeframe: '15',
              }, null, 2)}</pre>
            </GlassPanel>
          </div>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* GUIDE TAB                                                      */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'guide' && (
          <div>
            {/* Setup Guide */}
            <GlassPanel className={s.tvSetupCard} style={{ padding: pad }}>
              <SectionHeader title="TradingView Setup Guide" sub="Follow these steps to connect TradingView to Aura Alpha" />
              <ol className={s.tvStepList}>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>1</span>
                  <span>Go to the <strong style={{ color: C.text }}>Setup</strong> tab and click <strong style={{ color: C.text }}>Generate Webhook URL + API Key</strong> to get your unique endpoint</span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>2</span>
                  <span>Open any chart on <strong style={{ color: C.text }}>TradingView</strong> and click the <strong style={{ color: C.text }}>Alert</strong> button (clock icon) or press <code className={s.inlineCode}>Alt+A</code></span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>3</span>
                  <span>Configure your alert condition -- use any indicator, strategy, or price level</span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>4</span>
                  <span>In the <strong style={{ color: C.text }}>Notifications</strong> tab, check <strong style={{ color: C.text }}>Webhook URL</strong></span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>5</span>
                  <span>Paste your unique webhook URL (from the Setup tab) into the URL field</span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>6</span>
                  <span>In the <strong style={{ color: C.text }}>Message</strong> field, paste one of the message templates below</span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>7</span>
                  <span>Click <strong style={{ color: C.text }}>Create</strong> -- your TradingView signals will now flow to Aura Alpha automatically</span>
                </li>
                <li className={s.tvStep}>
                  <span className={s.tvStepNum}>8</span>
                  <span>Use the <strong style={{ color: C.text }}>Test</strong> tab to send a simulated signal and verify everything works</span>
                </li>
              </ol>
            </GlassPanel>

            {/* Message Templates */}
            <GlassPanel className={s.tvSetupCard} style={{ padding: pad }}>
              <SectionHeader title="Message Templates" sub="Copy-paste these into TradingView's alert message field. Variables like {{ticker}} are auto-replaced by TradingView." />

              <div className={s.tvTemplateSection}>
                <div className={s.tvTemplateName}>Full JSON (recommended)</div>
                <div className={s.tvTemplateDesc}>Sends symbol, side, price, quantity, strategy name, and timeframe</div>
                <div className={s.tvTemplateBox}>
                  <pre className={s.tvTemplatePre}>{`{
  "symbol": "{{ticker}}",
  "side": "{{strategy.order.action}}",
  "price": {{close}},
  "quantity": {{strategy.order.contracts}},
  "strategy": "{{strategy.order.comment}}",
  "timeframe": "{{interval}}"
}`}</pre>
                  <div className={s.tvTemplateCopy}>
                    <CopyButton text={`{\n  "symbol": "{{ticker}}",\n  "side": "{{strategy.order.action}}",\n  "price": {{close}},\n  "quantity": {{strategy.order.contracts}},\n  "strategy": "{{strategy.order.comment}}",\n  "timeframe": "{{interval}}"\n}`} />
                  </div>
                </div>
              </div>

              <div className={s.tvTemplateSection}>
                <div className={s.tvTemplateName}>Simple JSON</div>
                <div className={s.tvTemplateDesc}>Minimal -- just symbol, side, and price. Aura Alpha auto-sizes the position.</div>
                <div className={s.tvTemplateBox}>
                  <pre className={s.tvTemplatePre}>{`{
  "symbol": "{{ticker}}",
  "side": "{{strategy.order.action}}",
  "price": {{close}}
}`}</pre>
                  <div className={s.tvTemplateCopy}>
                    <CopyButton text={`{\n  "symbol": "{{ticker}}",\n  "side": "{{strategy.order.action}}",\n  "price": {{close}}\n}`} />
                  </div>
                </div>
              </div>

              <div className={s.tvTemplateSection}>
                <div className={s.tvTemplateName}>Pine Script Strategy</div>
                <div className={s.tvTemplateDesc}>One-liner for strategy alerts -- uses TradingView variables directly</div>
                <div className={s.tvTemplateBox}>
                  <pre className={s.tvTemplatePre}>{'{{strategy.order.action}} {{ticker}} @ {{close}}'}</pre>
                  <div className={s.tvTemplateCopy}>
                    <CopyButton text="{{strategy.order.action}} {{ticker}} @ {{close}}" />
                  </div>
                </div>
              </div>

              <div className={s.tvTemplateSection}>
                <div className={s.tvTemplateName}>Close Position</div>
                <div className={s.tvTemplateDesc}>Exits an entire position in the specified symbol</div>
                <div className={s.tvTemplateBox}>
                  <pre className={s.tvTemplatePre}>{`{
  "symbol": "{{ticker}}",
  "close_all": true
}`}</pre>
                  <div className={s.tvTemplateCopy}>
                    <CopyButton text={`{\n  "symbol": "{{ticker}}",\n  "close_all": true\n}`} />
                  </div>
                </div>
              </div>

              <div className={s.tvTemplateSection}>
                <div className={s.tvTemplateName}>With Bot Routing</div>
                <div className={s.tvTemplateDesc}>Explicitly specify which bot should execute the signal</div>
                <div className={s.tvTemplateBox}>
                  <pre className={s.tvTemplatePre}>{`{
  "symbol": "{{ticker}}",
  "side": "{{strategy.order.action}}",
  "price": {{close}},
  "quantity": {{strategy.order.contracts}},
  "bot": "SHAWN"
}`}</pre>
                  <div className={s.tvTemplateCopy}>
                    <CopyButton text={`{\n  "symbol": "{{ticker}}",\n  "side": "{{strategy.order.action}}",\n  "price": {{close}},\n  "quantity": {{strategy.order.contracts}},\n  "bot": "SHAWN"\n}`} />
                  </div>
                </div>
              </div>
            </GlassPanel>

            {/* TradingView Requirements */}
            <GlassPanel style={{ padding: pad }}>
              <SectionHeader title="Requirements" sub="What you need to use TradingView webhooks" />
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                <div className={s.tvRoute}>
                  <div className={s.tvRouteName} style={{ color: C.blue }}>TradingView Pro+ or higher</div>
                  <div className={s.tvRouteDesc}>Webhook alerts require TradingView Pro, Pro+, or Premium plan. The free plan does not support webhooks.</div>
                </div>
                <div className={s.tvRoute}>
                  <div className={s.tvRouteName} style={{ color: C.green }}>Aura Alpha Trader tier or higher</div>
                  <div className={s.tvRouteDesc}>Webhook integration is available on the Trader ($49/mo) plan and above.</div>
                </div>
                <div className={s.tvRoute}>
                  <div className={s.tvRouteName} style={{ color: C.amber }}>Valid API Key</div>
                  <div className={s.tvRouteDesc}>Your webhook URL includes an API key for authentication. Keep it secret and rotate it if compromised.</div>
                </div>
              </div>
            </GlassPanel>
          </div>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* AUDIT LOG TAB                                                  */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {tab === 'audit' && (
          <GlassPanel style={{ padding: 0 }}>
            <div style={{ padding: `${pad}px ${pad}px 12px` }}>
              <div className={s.sectionHeaderRow}>
                <SectionHeader
                  title="Webhook Audit Log"
                  sub="All webhook-related events: key creation, revocation, webhook deliveries, errors, and configuration changes."
                />
                <button
                  onClick={() => fetchAuditEvents(abortRef.current?.signal)}
                  className={s.actionBtn}
                >
                  Refresh
                </button>
              </div>
            </div>
            {auditLoading ? (
              <div className={s.emptyState}>Loading audit events...</div>
            ) : auditEvents.length === 0 ? (
              <div className={s.emptyState}>
                No audit events yet. Events will appear here as you use the webhook system.
              </div>
            ) : (
              <div>
                {auditEvents.map((evt, i) => (
                  <div key={evt.id || i} className={s.auditRow}>
                    <span className={s.auditAction} style={{
                      color: (evt.action || evt.event_type || '').includes('revoke') ? '#EF4444'
                        : (evt.action || evt.event_type || '').includes('create') ? '#22C55E'
                        : (evt.action || evt.event_type || '').includes('error') ? '#F59E0B'
                        : '#60A5FA',
                    }}>
                      {evt.action || evt.event_type || evt.type || 'event'}
                    </span>
                    <span className={s.auditDetail}>
                      {evt.detail || evt.description || evt.message || JSON.stringify(evt.metadata || {})}
                    </span>
                    <span className={s.auditTime}>
                      {fmtTime(evt.created_at || evt.timestamp)}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </GlassPanel>
        )}
      </div>
    </AnimatedPage>
  );
}
